changeSet.sql:
UPDATE clinlims.menu SET is_active = false
  WHERE element_id = 'menu_reports_auditTrail'
    AND parent_id != (SELECT id FROM clinlims.menu WHERE element_id = 'menu_reports');
UPDATE clinlims.menu SET is_active = false WHERE element_id = 'menu_reports_auditTrail.study';

-- Clear the action_url so the parent becomes a non-navigating folder UPDATE clinlims.menu SET action_url = '' WHERE element_id = 'menu_reports_audittrail';
-- Add "System Events" child menu item INSERT INTO clinlims.menu (id, parent_id, presentation_order, element_id, action_url, display_key, is_active) SELECT nextval('clinlims.menu_seq'), (SELECT id FROM clinlims.menu WHERE element_id = 'menu_reports_audittrail'), 1, 'menu_reports_audittrail_system', '/AuditTrailReport?type=system', 'sideNav.label.audittrail.systemEvents', true WHERE NOT EXISTS (SELECT 1 FROM clinlims.menu WHERE element_id = 'menu_reports_audittrail_system');
-- Add "Order Events" child menu item INSERT INTO clinlims.menu (id, parent_id, presentation_order, element_id, action_url, display_key, is_active) SELECT nextval('clinlims.menu_seq'), (SELECT id FROM clinlims.menu WHERE element_id = 'menu_reports_audittrail'), 2, 'menu_reports_audittrail_order', '/AuditTrailReport?type=order', 'sideNav.label.audittrail.orderEvents', true WHERE NOT EXISTS (SELECT 1 FROM clinlims.menu WHERE element_id = 'menu_reports_audittrail_order');

CREATE INDEX IF NOT EXISTS idx_history_timestamp_reftable
  ON clinlims.history (timestamp DESC, reference_table);
CREATE INDEX IF NOT EXISTS idx_history_sys_user_id
  ON clinlims.history (sys_user_id);
